## 4. Empty States

### Approach
A reusable `<EmptyState>` component with icon, title, description, and optional CTA. Used when a board has no columns, a column has no tickets, or a filter returns no results.

### Implementation

```tsx
// src/components/EmptyState.tsx
import { ReactNode } from 'react'

interface EmptyStateProps {
  icon: ReactNode
  title: string
  description: string
  action?: { label: string; onClick: () => void }
}

export function EmptyState({ icon, title, description, action }: EmptyStateProps) {
  return (
    <div className="empty-state" role="status">
      <div className="empty-state-icon">{icon}</div>
      <h3>{title}</h3>
      <p>{description}</p>
      {action && (
        <button onClick={action.onClick}>{action.label}</button>
      )}
    </div>
  )
}
```

### Usage Examples

```tsx
// src/components/BoardView.tsx
import { EmptyState } from './EmptyState'

export function BoardView() {
  const { columns } = useBoardData()

  if (columns.length === 0) {
    return (
      <EmptyState
        icon="📋"
        title="No columns yet"
        description="Create your first column to start organizing tickets."
        action={{ label: 'Add Column', onClick: openColumnDialog }}
      />
    )
  }
  return (/* board render */)
}
```

```tsx
// src/components/Column.tsx
export function Column({ column }: { column: Column }) {
  if (column.tickets.length === 0) {
    return (
      <EmptyState
        icon="🎫"
